import{_ as t,o,c as s,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"50. Roster","description":"","frontmatter":{"title":"50. Roster","eba":"Allied Health Professionals 2021-2026","topics":["hours","rosters","on-call"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/50-roster.md","filePath":"ebas/allied-health/hours-of-work/50-roster.md"}'),r={name:"ebas/allied-health/hours-of-work/50-roster.md"};function n(i,e,l,p,h,c){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="_50-roster" tabindex="-1">50. Roster <a class="header-anchor" href="#_50-roster" aria-label="Permalink to &quot;50. Roster&quot;">​</a></h1><p><strong>50.1</strong> Posting a Roster</p><p><strong>(a)</strong> A roster of at least a fortnight setting out:</p><p><strong>(i)</strong> hours of duty;</p><p><strong>(ii)</strong> on-call requirements;</p><p><strong>(iii)</strong> meal times;</p><p><strong>(iv)</strong> start and finish times;</p><p><strong>(v)</strong> weekend duty;</p><p><strong>(vi)</strong> night duty; and</p><p><strong>(vii)</strong> other such duty as in accordance with this Agreement; will be posted in a place or places to allow an Employee covered by this Agreement to have ready access to the roster while at work, which may include ready electronic access.</p><p><strong>(b)</strong> The roster will be posted at least two (2) weeks prior to becoming effective.</p><p><strong>50.2</strong> Altering a roster</p><p><strong>(a)</strong> A roster set in accordance with subclause 50.1 will only be altered by the Employer to enable the functions of the Employer to be carried on where another Employee is absent from duty pursuant to:</p><p><strong>(i)</strong> the reasons specified at subclause 62.3(a)(i) and (ii) (Personal Leave (including Carer’s Leave));</p><p><strong>(ii)</strong> <a href="/eba/ebas/allied-health/leave/67-compassionate-leave.html">Clause 67</a> – compassionate leave;</p><p><strong>(iii)</strong> <a href="/eba/ebas/allied-health/leave/75-ceremonial-leave.html">Clause 75</a> – ceremonial leave;</p><p><strong>(iv)</strong> <a href="/eba/ebas/allied-health/leave/66-family-violence-leave.html">Clause 66</a> – family violence leave; or</p><p><strong>(v)</strong> resignation of an Employee where the Employee has not provided notice to the Employer; or due to any pressing emergency.</p><p><strong>(b)</strong> Where the Employer changes an Employee’s roster once set in accordance with subclause 50.1 without at least seven (7) days’ notice, other than as excepted at subclause 50.2(c) below, the Employee will be paid the Change of Roster Allowance as follows in relation to each change :</p><p><strong>(i)</strong> 2.5% of the AHP1 Grade 1, Year 2 rate.</p><p><strong>(c)</strong> The Change of Roster Allowance at subclause 50.2(b) is not payable where:</p><p><strong>(i)</strong> the change to the roster was the result of an emergency situation external to the Employer;</p><p><strong>(ii)</strong> a part time employee is offered and accepts an additional shift / shifts;</p><p><strong>(iii)</strong> the change to the roster was the result of a request of the Employee (which includes Employees agreeing to swap shifts). Biometr ic Timekeep ing</p>',24)])])}const m=t(r,[["render",n]]);export{d as __pageData,m as default};
